@app.route('/api/transaction', methods=['POST'])
@track_metrics
def create_transaction():
    """Business transaction endpoint with validation"""
    try:
        data = request.get_json(silent=True)
        if not data:
            return jsonify({'error': 'Invalid JSON'}), 400
        
        # Validate transaction type
        transaction_type = data.get('type', '').lower()
        if not validate_transaction_type(transaction_type):
            return jsonify({'error': 'Invalid transaction type'}), 400
        
        # Validate transaction value
        value = validate_numeric_input(data.get('value', 0), min_val=0, max_val=1000000)
        if value is None:
            return jsonify({'error': 'Invalid transaction value'}), 400
        
        # Track business metrics
        business_transactions.labels(transaction_type=transaction_type, status='success').inc()
        business_value.labels(transaction_type=transaction_type).observe(value)
        
        return jsonify({
            'status': 'success',
            'transaction_id': secrets.token_urlsafe(16),
            'type': transaction_type,
            'value': value
        }), 201
        
    except Exception as e:
        business_transactions.labels(transaction_type='unknown', status='error').inc()
        app.logger.error(f"Transaction error: {type(e).__name__}")
        return jsonify({'error': 'Internal server error'}), 500


@app.route('/api/data', methods=['GET'])
@track_metrics
def get_data():
    """Sample data endpoint"""
    # Validate query parameters
    limit = request.args.get('limit', '10')
    limit_value = validate_numeric_input(limit, min_val=1, max_val=100)
    
    if limit_value is None:
        return jsonify({'error': 'Invalid limit parameter'}), 400
    
    return jsonify({
        'data': [{'id': i, 'value': f'item_{i}'} for i in range(int(limit_value))],
        'count': int(limit_value)
    })


@app.route('/api/system/health', methods=['POST'])
@track_metrics
def update_health():
    """Update system health score"""
    try:
        data = request.get_json(silent=True)
        if not data:
            return jsonify({'error': 'Invalid JSON'}), 400
        
        score = validate_numeric_input(data.get('score', 0), min_val=0, max_val=100)
        if score is None:
            return jsonify({'error': 'Invalid health score'}), 400
        
        system_health.set(score)
        return jsonify({'status': 'updated', 'health_score': score})
        
    except Exception as e:
        app.logger.error(f"Health update error: {type(e).__name__}")
        return jsonify({'error': 'Internal server error'}), 500


